        sum_a = (sum_a + term_half) % MOD;
        const term_sq = (term_half * term_half) % MOD;
        sum_a_sq = (sum_a_sq + term_sq) % MOD;
    }
    const sum_a_squared = (sum_a * sum_a) % MOD;
    const numerator = (sum_a_squared - sum_a_sq + MOD) % MOD;
